import{_ as e,c as a,o as t,a2 as i}from"./chunks/framework.DdOM6S6U.js";const u=JSON.parse('{"title":"File Storage with Filepond","description":"","frontmatter":{"outline":"deep","sidebarPos":5},"headers":[],"relativePath":"guide/generics/file-storage-with-filepond.md","filePath":"guide/generics/file-storage-with-filepond.md","lastUpdated":null}'),o={name:"guide/generics/file-storage-with-filepond.md"},s=i('<h1 id="file-storage-with-filepond" tabindex="-1">File Storage with Filepond <a class="header-anchor" href="#file-storage-with-filepond" aria-label="Permalink to &quot;File Storage with Filepond&quot;">​</a></h1><p><code>Modularity</code> provides two different file storage functionality, with file library method and filepond. These two systems, differentiate over <code>file - fileable object</code> relationship and input component used over forms. This documentation will only cover the filepond mechanism.</p><h2 id="storage-mechanism" tabindex="-1">Storage Mechanism <a class="header-anchor" href="#storage-mechanism" aria-label="Permalink to &quot;Storage Mechanism&quot;">​</a></h2><p>Filepond storage mechanism is design based on <a href="https://pqina.nl/filepond/docs/api/server/" target="_blank" rel="noreferrer">FilePond Vue Component Docs</a>, which requires and serves <code>temporary asset</code> processing. For an example, let&#39;s say project have system users and users can upload their avatar(s).</p><ul><li>When a file is uplaoded through the FilePond interface, it is sent to our backend via a secure API endpoint.</li><li>Then, our <code>FilePondManager</code> processes the file upload request, performs necessary validations and stores the file in temporary file storage path and file data in <code>temporary file table</code>.</li><li>During this stage, the file is cached to echance performance and allow for any further processing or validation checks. And it is ready for permanent storage</li><li>Once the associated model form is confirmed or saved, the file is then moved from the temporary cache to its permanent storage location and a file object will be created on the permanent asset table.</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>This approach ensures efficient file handling, reducing the load on the system and improving the overall user experience. Our architecture ensures high reliability and scalability, capable of managing multiple concurrent uploads seamlessly.</p></div><p>Regarding the object relations, <code>modularity&#39;s filepond</code> offers <code>one to many polymorphic</code> relation between assetable objects and assets. Database structure can be observed below for user-assets mechanism.</p><img src="https://i.ibb.co/WvdQsCh/Screenshot-2024-07-23-at-11-53-36.png" alt="filepond_db_relations" border="0"><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>In order to implement and use filepond on file storage, see <a href="/guide/module-features/files-and-media">Files and Media</a> for the Filepond triple pattern.</p></div>',9),r=[s];function n(l,d,c,p,h,f){return t(),a("div",null,r)}const g=e(o,[["render",n]]);export{u as __pageData,g as default};
